+    #[test]
+    fn four_direction_changes() {
+        let mut coalescer = EventCoalescer::new();
+        let directions = [
+            MouseEventKind::ScrollUp,
+            MouseEventKind::ScrollDown,
+            MouseEventKind::ScrollLeft,
+            MouseEventKind::ScrollRight,
