+
+        let pending = coalescer.flush();
+        assert_eq!(pending.len(), 2);
+        // Scroll always first
+        assert!(matches!(
+            pending[0],
+            Event::Mouse(MouseEvent {
+                kind: MouseEventKind::ScrollUp,
+                ..
+            })
+        ));
+        assert!(matches!(
+            pending[1],
+            Event::Mouse(MouseEvent {
+                kind: MouseEventKind::Moved,
+                ..
+            })
+        ));
+    }
